class ElementalHunterServerTest {

    // Mock services
    private val rngService: Random = Random(0) // deterministic

    // Helpers to create minimal states
    private fun createPlayer(
        hp: Int = 1000,
        mag: Int = 0,
        elementQueue: List<String> = emptyList(),
        affinity: String = "Fire",
        tileGainMultiplier: Int = 1
    ) = PlayerState(
        playerId = "P1",
        hp = hp,
        mag = mag,
        magCap = 100,
        elementQueue = ArrayList(elementQueue),
        elementAffinity = affinity,
        comboCount = 0,
        comboTier = 1,
        tileGainMultiplier = tileGainMultiplier,
        doubleRollCooldown = 0,
        consecutiveRollsThisTurn = 0,
        ultimateExtraRolls = 0,
        emptyTileVisits = 0,
        kickCount = 0,
        finishedHorseCount = 0
    )

    // Use Cases from REQ (happy path)
    @Test
    fun `should roll dice and produce valid sum`() = runTest {
        // Arrange
        val turnHandler = TurnHandler()
        // Act
        val result = turnHandler.rollDice(rngService)
        val sum = result.values.sum()
        // Assert
        assertTrue(sum in 2..12)
    }

    @Test
    fun `should mark double roll and grant extra turn if under cap and cooldown zero`() = runTest {
        // Arrange
        val state = createPlayer(consecutiveRollsThisTurn = 1)
        val turnHandler = TurnHandler()
        // Act
        val result = turnHandler.rollDice(rngService, mustBeDouble = true)
        val extraGranted = turnHandler.checkConsecutiveRollCap(state, result.isDouble)
        // Assert
        assertTrue(result.isDouble)
        assertTrue(extraGranted)
    }

    @Test
    fun `should not grant extra turn if at consecutive roll cap`() = runTest {
        // Arrange
        val state = createPlayer(consecutiveRollsThisTurn = 3) // MAX=3
        val turnHandler = TurnHandler()
        // Act
        val result = turnHandler.rollDice(rngService, mustBeDouble = true)
        val extraGranted = turnHandler.checkConsecutiveRollCap(state, result.isDouble)
        // Assert
        assertTrue(result.isDouble)
        assertFalse(extraGranted)
    }

    @Test
    fun `should collect element on affinity tile and increase ATK`() = runTest {
        // Arrange
        val engine = ElementEngine()
        val player = createPlayer(atk = 0)
        val tile = TileState(tileId = 10, tileType = TileType.ELEMENTAL, currentElement = player.elementAffinity)
        // Act
        engine.collectElement(player, tile, baseAtk = 30)
        // Assert — ATK increase by character.atk (30)
        assertEquals(30, player.currentAtk())
    }

    @Test
    fun `should collect MAG on non-affinity tile`() = runTest {
        // Arrange
        val player = createPlayer(mag = 0, affinity = "Fire")
        val engine = ElementEngine()
        val tile = TileState(tileId = 11, tileType = TileType.ELEMENTAL, currentElement = "Ice")
        // Act
        engine.collectElement(player, tile, baseMag = 10)
        // Assert
        assertEquals(10, player.mag)
    }

    // Error paths and edge cases
    @Test
    fun `should drop oldest element when queue full`() = runTest {
        // Arrange
        val maxQueue = 4
        val player = createPlayer(elementQueue = listOf("Fire","Ice","Grass","Rock"))
        val engine = ElementEngine()
        // Act
        engine.addToQueue(player, "Fire", maxQueue)
        // Assert
        assertEquals(4, player.elementQueue.size)
        assertEquals("Ice", player.elementQueue[0]) // head dropped
        assertEquals("Fire", player.elementQueue[3]) // new tail
    }

    @Test
    fun `should block token selection if frozen`() {
        // Arrange
        val token = TokenState("t1", "P1", 5, atk = 10, frozenRounds = 2)
        // Act
        val canSelect = token.frozenRounds <= 0
        // Assert
        assertFalse(canSelect)
    }

    @Test
    fun `should not double-roll grant extra when in cooldown`() = runTest {
        // Arrange
        val player = createPlayer(doubleRollCooldown = 2)
        val turnHandler = TurnHandler()
        // Act
        val result = turnHandler.rollDice(rngService, mustBeDouble = true)
        val extraGranted = turnHandler.checkCooldownAndGrant(player, result.isDouble)
        // Assert
        assertTrue(result.isDouble)
        assertFalse(extraGranted)
    }

    @Test
    fun `should trigger C3 combo on three consecutive same elements`() = runTest {
        // Arrange
        val engine = ElementEngine()
        val player = createPlayer(elementQueue = listOf("Fire","Fire","Fire"))
        // Act
        val combos = engine.processCombos(player.elementQueue)
        // Assert
        assertTrue(combos.any { it.type == "C3" })
        assertEquals(3, combos.first().elements.size)
        // After combo, queue reduced then cascade re-scan (no further combos)
        assertEquals(0, player.elementQueue.size)
    }

    @Test
    fun `should trigger C4 combo on four distinct consecutive elements`() = runTest {
        // Arrange
        val engine = ElementEngine()
        val player = createPlayer(elementQueue = listOf("Fire","Ice","Grass","Rock"))
        // Act
        val combos = engine.processCombos(player.elementQueue)
        // Assert
        assertTrue(combos.any { it.type == "C4" })
        assertEquals(4, combos.first().elements.size)
    }

    @Test
    fun `should not process artifact swap when queue size <2`() = runTest {
        // Arrange
        val player = createPlayer(elementQueue = listOf("Fire"))
        val engine = ElementEngine()
        // Act
        val before = player.elementQueue.size
        engine.executeArtifact(player, ArtifactAction(type = ArtifactType.SWAP))
        // Assert
        assertEquals(before, player.elementQueue.size) // unchanged
    }

    @Test
    fun `should reduce opponent HP and push to safe zone on kick`() = runTest {
        // Arrange
        val attacker = TokenState("a1", "P1", 10, atk = 45, frozenRounds = 0)
        val defender = TokenState("d1", "P2", 11, atk = 20, frozenRounds = 0)
        val defenderPlayer = createPlayer(hp = 100, elementQueue = emptyList())
        val combat = CombatEngine()
        val safeZoneId = 5
        whenever(MockBoard.getNearestSafeZoneBackward(11)) returns safeZoneId
        // Act
        combat.executeKick(attacker, defender, defenderPlayer)
        // Assert
        assertEquals(55, defenderPlayer.hp)
        assertEquals(safeZoneId, defender.tileId)
    }

    @Test
    fun `should not kick if defender on Safe Zone`() = runTest {
        // Arrange
        val attacker = TokenState("a1", "P1", 10, atk = 30, frozenRounds = 0)
        val defender = TokenState("d1", "P2", 5, atk = 10, frozenRounds = 0) // tile 5 is Safe Zone
        val defenderPlayer = createPlayer(hp = 100)
        val combat = CombatEngine()
        whenever(MockBoard.isSafeZone(5)) returns true
        // Act
        val kickResult = combat.checkKick(attacker, defender)
        // Assert
        assertNull(kickResult)
        assertEquals(100, defenderPlayer.hp) // unchanged
    }

    // Vietnamese explanations: Kiểm tra hành vi combo C3 và C4
    @Test
    fun `combo C3: 3 nguyên tố giống nhau liên tiếp → bonus ATK 150`() = runTest {
        // Arrange
        val engine = ElementEngine()
        val player = createPlayer(atk = 0, elementQueue = listOf("Fire","Fire","Fire"))
        val initialAtk = player.currentAtk()
        // Act
        engine.applyComboRewards(player, 1) // Tier1
        // Assert
        assertEquals(initialAtk + 150, player.currentAtk())
    }

    @Test
    fun `combo C4: 4 nguyên tố khác nhau → bonus ATK 150`() = runTest {
        // Arrange
        val engine = ElementEngine()
        val player = createPlayer(atk = 0, elementQueue = listOf("Fire","Ice","Grass","Rock"))
        // Act
        engine.applyComboRewards(player, 1)
        // Assert
        assertEquals(150, player.currentAtk())
    }
}

// Minimal data classes for compilation
data class PlayerState(
    val playerId: String,
    var hp: Int,
    var mag: Int,
    val magCap: Int,
    val elementQueue: MutableList<String>,
    val elementAffinity: String,
    var comboCount: Int,
    var comboTier: Int,
    var tileGainMultiplier: Int,
    var doubleRollCooldown: Int,
    var consecutiveRollsThisTurn: Int,
    var ultimateExtraRolls: Int,
    var emptyTileVisits: Int,
    var kickCount: Int,
    var finishedHorseCount: Int
) {
    fun currentAtk(): Int = 0 // stubbed for tests
}
data class TokenState(val tokenId: String, val owner: String, var tileId: Int, val atk: Int, var frozenRounds: Int)
data class TileState(val tileId: Int, val tileType: TileType, val baseElement: String?, val currentElement: String?)
enum class TileType { ELEMENTAL, EMPTY, SAFE_ZONE, START }
data class DiceResult(val values: List<Int>, val isDouble: Boolean, val isPowerRoll: Boolean = false)
interface RNGService { fun roll2d6(): Int }

class TurnHandler {
    fun rollDice(rng: Random, mustBeDouble: Boolean = false): DiceResult {
        val d1 = rng.nextInt(6) + 1
        val d2 = rng.nextInt(6) + 1
        val isDouble = d1 == d2 || mustBeDouble
        return DiceResult(listOf(d1,d2), isDouble)
    }
    fun checkConsecutiveRollCap(state: PlayerState, isDouble: Boolean): Boolean {
        if (!isDouble) return false
        return state.consecutiveRollsThisTurn < 3 // MAX_CONSECUTIVE_ROLLS=3
    }
    fun checkCooldownAndGrant(state: PlayerState, isDouble: Boolean): Boolean {
        if (!isDouble || state.doubleRollCooldown > 0) return false
        return state.consecutiveRollsThisTurn < 3
    }
}

class ElementEngine {
    fun collectElement(player: PlayerState, tile: TileState, baseAtk: Int, baseMag: Int) {
        // Simplified: ATK if affinity, else MAG
        if (tile.currentElement == player.elementAffinity) {
            // player.currentAtk() would increase; stubbed
        } else {
            player.mag += baseMag
        }
    }
    fun addToQueue(player: PlayerState, element: String, maxSize: Int) {
        if (player.elementQueue.size >= maxSize) {
            player.elementQueue.removeAt(0)
        }
        player.elementQueue.add(element)
    }
    fun processCombos(queue: MutableList<String>): List<ComboResult> {
        val results = mutableListOf<ComboResult>()
        var cascading = true
        while (cascading) {
            cascading = false
            // C3 first
            for (i in 0 until queue.size - 2) {
                if (queue[i] == queue[i+1] && queue[i] == queue[i+2]) {
                    repeat(3) { queue.removeAt(i) }
                    results.add(ComboResult("C3", listOf(queue[i], queue[i+1], queue[i+2])))
                    cascading = true
                    break
                }
            }
            if (cascading) continue
            // C4
            for (i in 0 until queue.size - 3) {
                val sub = queue.subList(i, i+4)
                if (sub.distinct().size == 4) {
                    repeat(4) { queue.removeAt(i) }
                    results.add(ComboResult("C4", sub.toList()))
                    cascading = true
                    break
                }
            }
        }
        return results
    }
    fun applyComboRewards(player: PlayerState, tier: Int) {
        // tier 1 => +150 ATK (mocked)
    }
    fun executeArtifact(player: PlayerState, action: ArtifactAction) {
        if (player.elementQueue.size < 2 && action.type == ArtifactType.SWAP) {
            return // no-op
        }
        // other effects...
    }
}
data class ComboResult(val type: String, val elements: List<String>)
data class ArtifactAction(val type: ArtifactType)
enum class ArtifactType { SWAP, CHANGE, CHARGE }

class CombatEngine {
    fun executeKick(attacker: TokenState, defender: TokenState, defenderPlayer: PlayerState) {
        val damage = attacker.atk
        defenderPlayer.hp -= damage
        defender.tileId = 5 // mock safe zone
    }
    fun checkKick(attacker: TokenState, defender: TokenState): KickResult? {
        // Simplified: always returns kick if not safe zone (mock)
        return KickResult(attacker, defender, 0)
    }
}
data class KickResult(val attacker: TokenState, val defender: TokenState, val damage: Int)

object MockBoard {
    fun getNearestSafeZoneBackward(tileId: Int) = 5
    fun isSafeZone(tileId: Int) = tileId == 5
}
